INSERT INTO content_section_translation (content_section_id, language_id, title, body)
VALUES
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'overview'),
   (SELECT id FROM language WHERE code = 'es'), 'Descripción General',
   E'API RESTful construida con Django y Django REST Framework que sirve como núcleo de la plataforma StreamFlow Music. Gestiona todo el ciclo de vida del contenido musical: procesamiento e ingesta de tracks desde fuentes externas (Spotify/YouTube), extracción automática de metadatos de artistas, álbumes y géneros, y almacenamiento normalizado en PostgreSQL.\n\nImplementa un diseño modular de servicios con SongDatabaseService para persistencia de canciones, MediaProcessor para transformación de datos multimedia, y MusicDataConverter para normalización de formatos entre fuentes externas y el modelo de dominio interno.\n\nEl sistema soporta gestión de perfiles de usuario con carga de imágenes a Supabase Storage, operaciones CRUD completas de playlists, y autenticación integrada con Supabase Auth.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'overview'),
   (SELECT id FROM language WHERE code = 'en'), 'Overview',
   E'RESTful API built with Django and Django REST Framework that serves as the core of the StreamFlow Music platform. It manages the entire music content lifecycle: track processing and ingestion from external sources (Spotify/YouTube), automatic extraction of artist, album, and genre metadata, and normalized storage in PostgreSQL.\n\nIt implements a modular service design with SongDatabaseService for song persistence, MediaProcessor for multimedia data transformation, and MusicDataConverter for format normalization between external sources and the internal domain model.\n\nThe system supports user profile management with image uploads to Supabase Storage, full playlist CRUD operations, and integrated Supabase Auth authentication.'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'architecture'),
   (SELECT id FROM language WHERE code = 'es'), 'Arquitectura',
   E'Arquitectura Limpia estricta aplicada en todas las apps Django con cuatro capas bien definidas:\n\n• **Dominio:** Entidades puras como SongEntity e ISongRepository que encapsulan reglas de negocio sin dependencias externas\n• **Casos de uso:** Orquestadores como SaveTrackAsSongUseCase, GetUserProfileUseCase y UploadProfilePicture que coordinan la lógica de aplicación\n• **Infraestructura:** Modelos ORM de Django, implementaciones concretas de repositorios y mappers entre capas\n• **API:** ViewSets, DTOs serializables con DRF y documentación automática con drf-spectacular\n\nLos settings están modularizados en archivos independientes: base, database, auth, REST framework y Supabase, permitiendo configuración granular por entorno.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'architecture'),
   (SELECT id FROM language WHERE code = 'en'), 'Architecture',
   E'Strict Clean Architecture applied across all Django apps with four well-defined layers:\n\n• **Domain:** Pure entities like SongEntity and ISongRepository that encapsulate business rules without external dependencies\n• **Use Cases:** Orchestrators like SaveTrackAsSongUseCase, GetUserProfileUseCase, and UploadProfilePicture that coordinate application logic\n• **Infrastructure:** Django ORM models, concrete repository implementations, and inter-layer mappers\n• **API:** ViewSets, DRF-serializable DTOs, and automatic documentation with drf-spectacular\n\nSettings are modularized into independent files: base, database, auth, REST framework, and Supabase, enabling granular per-environment configuration.'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'features'),
   (SELECT id FROM language WHERE code = 'es'), 'Funcionalidades',
   E'• Procesamiento y guardado de tracks musicales desde fuentes Spotify y YouTube con normalización automática de metadatos\n• Extracción inteligente de artistas, álbumes y géneros con deduplicación y relaciones many-to-many\n• Gestión de perfiles de usuario con carga de imágenes a Supabase Storage y validación de formatos\n• Operaciones CRUD completas de playlists con ordenamiento personalizable y paginación\n• Autenticación integrada con Supabase Auth mediante middleware personalizado\n• FilteredViewSetMixin y CRUDViewSetMixin reutilizables que reducen boilerplate en endpoints\n• Documentación de esquemas API generada automáticamente con drf-spectacular\n• Endpoints paginados mediante decorador @paginated_list_endpoint para respuestas consistentes'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'features'),
   (SELECT id FROM language WHERE code = 'en'), 'Features',
   E'• Music track processing and saving from Spotify and YouTube sources with automatic metadata normalization\n• Smart extraction of artists, albums, and genres with deduplication and many-to-many relationships\n• User profile management with image uploads to Supabase Storage and format validation\n• Full playlist CRUD operations with customizable sorting and pagination\n• Integrated Supabase Auth authentication via custom middleware\n• Reusable FilteredViewSetMixin and CRUDViewSetMixin that reduce endpoint boilerplate\n• Auto-generated API schema documentation with drf-spectacular\n• Paginated endpoints via @paginated_list_endpoint decorator for consistent responses'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'testing'),
   (SELECT id FROM language WHERE code = 'es'), 'Testing',
   E'Más de 474 tests unitarios con cero fallos ejecutados con pytest. La suite de tests cubre exhaustivamente cada capa de la arquitectura:\n\n• **Tests de dominio:** Validación de entidades (SongEntity, ArtistEntity) y reglas de negocio\n• **Tests de casos de uso:** Verificación de flujos completos con mocks de repositorios usando AsyncMock\n• **Tests de DTOs:** TestSongCreateDTO y TestSongMapper validan transformaciones y restricciones de datos\n• **Tests de API:** Endpoints probados con TestClient asegurando respuestas HTTP correctas\n\nIncluye pytest-asyncio para operaciones asíncronas, reportes de cobertura en formato XML integrados con SonarCloud, y un Quality Gate que garantiza umbrales mínimos de cobertura.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'testing'),
   (SELECT id FROM language WHERE code = 'en'), 'Testing',
   E'474+ unit tests with zero failures executed with pytest. The test suite exhaustively covers each architecture layer:\n\n• **Domain tests:** Entity validation (SongEntity, ArtistEntity) and business rules\n• **Use case tests:** Full flow verification with repository mocks using AsyncMock\n• **DTO tests:** TestSongCreateDTO and TestSongMapper validate data transformations and constraints\n• **API tests:** Endpoints tested with TestClient ensuring correct HTTP responses\n\nIncludes pytest-asyncio for async operations, XML coverage reports integrated with SonarCloud, and a Quality Gate that enforces minimum coverage thresholds.'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'api'),
   (SELECT id FROM language WHERE code = 'es'), 'Diseño de API',
   E'Endpoints RESTful organizados por dominio: canciones, artistas, álbumes, géneros, playlists y perfiles de usuario. Cada recurso utiliza ViewSets (GenreViewSet, UserProfileViewSet) que heredan de los mixins personalizados del proyecto.\n\nToda la API está documentada con decoradores @extend_schema_view de drf-spectacular, generando documentación OpenAPI interactiva accesible desde el navegador.\n\nLos DTOs definen contratos claros de request/response con validación automática mediante serializers. Todas las respuestas de listas usan el decorador @paginated_list_endpoint para formato consistente con metadatos de paginación.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-backend') AND cs.section_key = 'api'),
   (SELECT id FROM language WHERE code = 'en'), 'API Design',
   E'RESTful endpoints organized by domain: songs, artists, albums, genres, playlists, and user profiles. Each resource uses ViewSets (GenreViewSet, UserProfileViewSet) inheriting from the project''s custom mixins.\n\nThe entire API is documented with drf-spectacular @extend_schema_view decorators, generating interactive OpenAPI documentation accessible from the browser.\n\nDTOs define clear request/response contracts with automatic serializer validation. All list responses use the @paginated_list_endpoint decorator for consistent formatting with pagination metadata.')
ON CONFLICT (content_section_id, language_id) DO NOTHING;

-- ============================================================
-- FRONTEND: streamflow-music-frontend
-- ============================================================
INSERT INTO content_section (entity_type, entity_id, section_key, icon, position, is_archived, is_pinned)
VALUES
  ('project', (SELECT id FROM project WHERE code = 'streamflow-music-frontend'), 'overview',      'info',               1, false, true),
  ('project', (SELECT id FROM project WHERE code = 'streamflow-music-frontend'), 'architecture',  'account_tree',       2, false, true),
  ('project', (SELECT id FROM project WHERE code = 'streamflow-music-frontend'), 'features',      'featured_play_list', 3, false, false),
  ('project', (SELECT id FROM project WHERE code = 'streamflow-music-frontend'), 'ui_ux',         'palette',            4, false, false),
  ('project', (SELECT id FROM project WHERE code = 'streamflow-music-frontend'), 'i18n',          'translate',          5, false, false)
ON CONFLICT DO NOTHING;

INSERT INTO content_section_translation (content_section_id, language_id, title, body)
VALUES
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'overview'),
   (SELECT id FROM language WHERE code = 'es'), 'Descripción General',
   E'SPA moderna construida con Angular 19+ y Server-Side Rendering que ofrece una experiencia de usuario fluida para explorar y reproducir música.\n\nEl reproductor de música global permite escuchar contenido mientras se navega por cualquier sección de la aplicación, con controles persistentes de play/pause, siguiente/anterior y barra de progreso.\n\nLa aplicación implementa tematización dinámica con Material Design que permite cambiar entre paletas de colores en tiempo real, autenticación completa con flujos de login/registro vía Supabase, y gestión de playlists con extracción automática de color dominante de las portadas de álbumes.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'overview'),
   (SELECT id FROM language WHERE code = 'en'), 'Overview',
   E'Modern SPA built with Angular 19+ and Server-Side Rendering that offers a smooth user experience for exploring and playing music.\n\nThe global music player allows listening to content while navigating any section of the application, with persistent play/pause, next/previous, and progress bar controls.\n\nThe application implements dynamic Material Design theming that allows switching between color palettes in real time, full authentication with login/register flows via Supabase, and playlist management with automatic dominant color extraction from album covers.'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'architecture'),
   (SELECT id FROM language WHERE code = 'es'), 'Arquitectura',
   E'Diseño dirigido por dominio con separación limpia entre capas:\n\n• **Casos de uso:** AuthSessionUseCase y ChangeLanguageUseCase encapsulan la lógica de aplicación\n• **Repositorios:** Interfaces abstractas como ILanguageRepository con tokens de inyección (LANGUAGE_REPOSITORY_TOKEN) permiten intercambiar implementaciones\n• **Implementaciones:** LanguageRepository maneja persistencia en localStorage con detección automática del idioma del navegador\n• **Servicios de presentación:** LanguageService, GlobalPlayerStateService y MaterialThemeService exponen signals reactivos para vinculación directa con la UI\n\nTodos los componentes son standalone con ChangeDetectionStrategy.OnPush para rendimiento óptimo.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'architecture'),
   (SELECT id FROM language WHERE code = 'en'), 'Architecture',
   E'Domain-driven design with clean layer separation:\n\n• **Use cases:** AuthSessionUseCase and ChangeLanguageUseCase encapsulate application logic\n• **Repositories:** Abstract interfaces like ILanguageRepository with injection tokens (LANGUAGE_REPOSITORY_TOKEN) allow implementation swapping\n• **Implementations:** LanguageRepository handles localStorage persistence with automatic browser language detection\n• **Presentation services:** LanguageService, GlobalPlayerStateService, and MaterialThemeService expose reactive signals for direct UI binding\n\nAll components are standalone with ChangeDetectionStrategy.OnPush for optimal performance.'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'features'),
   (SELECT id FROM language WHERE code = 'es'), 'Funcionalidades',
   E'• Reproductor de música global persistente con GlobalPlayerStateService que mantiene el estado de reproducción entre navegaciones\n• Tematización dinámica Material Design con MaterialThemeService y ThemeDirective que aplican paletas de colores en tiempo real\n• Autenticación completa con flujos de login, registro y recuperación de contraseña vía Supabase\n• Gestión de playlists con extracción automática del color dominante de las portadas\n• Biblioteca musical con tablas ordenables (MusicsTable) y soporte de reproducción inline (MusicsTablePlay)\n• Exploración y búsqueda de contenido con filtros por género, artista y álbum\n• Interceptores HTTP (AuthTokenInterceptor) que inyectan automáticamente tokens de autenticación\n• Documentación técnica generada con Compodoc accesible como sitio web'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'features'),
   (SELECT id FROM language WHERE code = 'en'), 'Features',
   E'• Persistent global music player with GlobalPlayerStateService that maintains playback state across navigations\n• Dynamic Material Design theming with MaterialThemeService and ThemeDirective applying color palettes in real time\n• Full authentication with login, register, and password recovery flows via Supabase\n• Playlist management with automatic dominant color extraction from cover art\n• Music library with sortable tables (MusicsTable) and inline playback support (MusicsTablePlay)\n• Content exploration and search with genre, artist, and album filters\n• HTTP interceptors (AuthTokenInterceptor) that automatically inject authentication tokens\n• Technical documentation generated with Compodoc accessible as a website'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'ui_ux'),
   (SELECT id FROM language WHERE code = 'es'), 'UI/UX',
   E'Sistema de estilos SCSS con variables y módulos (@use, @forward) que permiten composición de estilos sin duplicación. El cambio dinámico de temas se implementa mediante MaterialThemeService que actualiza los tokens de Material Design en tiempo de ejecución.\n\nLos layouts son completamente responsivos con breakpoints adaptados a móvil, tablet y desktop. Las directivas personalizadas como ThemeDirective aplican estilos reactivos basados en el tema seleccionado.\n\nLa integración de MatIcon en tablas musicales proporciona iconografía consistente, y cada componente mantiene estilos encapsulados que evitan colisiones globales.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'ui_ux'),
   (SELECT id FROM language WHERE code = 'en'), 'UI/UX',
   E'SCSS styling system with variables and modules (@use, @forward) enabling style composition without duplication. Dynamic theme switching is implemented via MaterialThemeService that updates Material Design tokens at runtime.\n\nLayouts are fully responsive with breakpoints adapted for mobile, tablet, and desktop. Custom directives like ThemeDirective apply reactive styles based on the selected theme.\n\nMatIcon integration in music tables provides consistent iconography, and each component maintains encapsulated styles that prevent global collisions.'),

  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'i18n'),
   (SELECT id FROM language WHERE code = 'es'), 'Internacionalización',
   E'Soporte completo de internacionalización con ngx-translate para inglés y español. El LanguageRepository detecta automáticamente el idioma del navegador del usuario en la primera visita y persiste la preferencia en localStorage para visitas posteriores.\n\nLanguageService expone signals reactivos que propagan cambios de idioma instantáneamente a toda la UI sin necesidad de recarga. El código es consciente de la plataforma con verificaciones typeof window para garantizar compatibilidad con SSR.'),
  ((SELECT cs.id FROM content_section cs WHERE cs.entity_type = 'project' AND cs.entity_id = (SELECT id FROM project WHERE code = 'streamflow-music-frontend') AND cs.section_key = 'i18n'),
   (SELECT id FROM language WHERE code = 'en'), 'Internationalization',
   E'Full internationalization support with ngx-translate for English and Spanish. LanguageRepository automatically detects the user''s browser language on first visit and persists the preference in localStorage for subsequent visits.\n\nLanguageService exposes reactive signals that propagate language changes instantly across the entire UI without requiring a reload. The code is platform-aware with typeof window checks to ensure SSR compatibility.')
ON CONFLICT (content_section_id, language_id) DO NOTHING;

COMMIT;
